    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //      {
        //          "id": "206849494",
        //          "amount": "0.01",
        //          "rate": "5598346.0",
        //          "pair": "btc_jpy",
        //          "order_type": "sell",
        //          "created_at": "2021-12-08T14:10:33.000Z"
        //      }
        //
        // fetchMyTrades (private) - example from docs
        //
        //      {
        //          "id": 38,
        //          "order_id": 49,
        //          "created_at": "2015-11-18T07:02:21.000Z",
        //          "funds": {
        //              "btc": "0.1",
        //              "jpy": "-4096.135"
        //                  },
        //           "pair": "btc_jpy",
        //           "rate": "40900.0",
        //           "fee_currency": "JPY",
        //           "fee": "6.135",
        //           "liquidity": "T",
        //           "side": "buy"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.parse8601(this.safeString(trade, "created_at"));
        Object id = this.safeString(trade, "id");
        Object priceString = this.safeString(trade, "rate");
        Object marketId = this.safeString(trade, "pair");
        market = this.safeMarket(marketId, market, "_");
        Object baseId = Helpers.GetValue(market, "baseId");
        Object quoteId = Helpers.GetValue(market, "quoteId");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object takerOrMaker = null;
        Object amountString = null;
        Object costString = null;
        Object side = null;
        Object fee = null;
        Object orderId = null;
        if (Helpers.isTrue(Helpers.inOp(trade, "liquidity")))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.safeString(trade, "liquidity"), "T")))
            {
                takerOrMaker = "taker";
            } else if (Helpers.isTrue(Helpers.isEqual(this.safeString(trade, "liquidity"), "M")))
            {
                takerOrMaker = "maker";
            }
            Object funds = this.safeValue(trade, "funds", new java.util.HashMap<String, Object>() {{}});
            amountString = this.safeString(funds, ((String)baseId));
            costString = this.safeString(funds, ((String)quoteId));
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", CoincheckCore.this.safeString(trade, "fee_currency") );
                put( "cost", CoincheckCore.this.safeString(trade, "fee") );
            }};
            side = this.safeString(trade, "side");
            orderId = this.safeString(trade, "order_id");
        } else
        {
            amountString = this.safeString(trade, "amount");
            side = this.safeString(trade, "order_type");
        }
        final Object finalSide = side;
        final Object finalOrderId = orderId;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalAmountString = amountString;
        final Object finalCostString = costString;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "datetime", CoincheckCore.this.iso8601(timestamp) );
            put( "timestamp", timestamp );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", finalSide );
            put( "order", finalOrderId );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", priceString );
            put( "amount", finalAmountString );
            put( "cost", finalCostString );
            put( "fee", finalFee );
        }}, market);
    }

