    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "pending", "pending" );
            put( "processing", "pending" );
            put( "finished", "ok" );
            put( "canceled", "canceled" );
            put( "confirmed", "pending" );
            put( "received", "ok" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        // {
        //       "id": 2,
        //       "amount": "0.05",
        //       "currency": "BTC",
        //       "address": "13PhzoK8me3u5nHzzFD85qT9RqEWR9M4Ty",
        //       "status": "confirmed",
        //       "confirmed_at": "2015-06-13T08:29:18.000Z",
        //       "created_at": "2015-06-13T08:22:18.000Z"
        //  }
        //
        // fetchWithdrawals
        //
        //  {
        //       "id": 398,
        //       "status": "finished",
        //       "amount": "242742.0",
        //       "currency": "JPY",
        //       "created_at": "2014-12-04T15:00:00.000Z",
        //       "bank_account_id": 243,
        //       "fee": "400.0",
        //       "is_fast": true
        //  }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(transaction, "id");
        Object timestamp = this.parse8601(this.safeString(transaction, "created_at"));
        Object address = this.safeString(transaction, "address");
        Object amount = this.safeNumber(transaction, "amount");
        Object currencyId = this.safeString(transaction, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"));
        Object updated = this.parse8601(this.safeString(transaction, "confirmed_at"));
        Object fee = null;
        Object feeCost = this.safeNumber(transaction, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", id );
            put( "txid", null );
            put( "timestamp", timestamp );
            put( "datetime", CoincheckCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", address );
            put( "addressTo", address );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", null );
            put( "amount", amount );
            put( "currency", code );
            put( "status", status );
            put( "updated", updated );
            put( "comment", null );
            put( "internal", null );
            put( "fee", finalFee );
        }};
    }

    public Object nonce()
    {
        return this.milliseconds();
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object url = Helpers.add(Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "rest"), "/"), this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(api, "public")))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
            }
        } else
        {
            this.checkRequiredCredentials();
            Object nonce = String.valueOf(this.nonce());
            Object queryString = "";
            if (Helpers.isTrue(Helpers.isEqual(method, "GET")))
            {
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    url = Helpers.add(url, Helpers.add("?", this.urlencode(this.keysort(query))));
                }
            } else
            {
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    body = this.urlencode(this.keysort(query));
                    queryString = body;
                }
            }
            Object auth = Helpers.add(Helpers.add(nonce, url), queryString);
            final Object finalNonce = nonce;
            headers = new java.util.HashMap<String, Object>() {{
                put( "Content-Type", "application/x-www-form-urlencoded" );
                put( "ACCESS-KEY", CoincheckCore.this.apiKey );
                put( "ACCESS-NONCE", finalNonce );
                put( "ACCESS-SIGNATURE", CoincheckCore.this.hmac(CoincheckCore.this.encode(auth), CoincheckCore.this.encode(CoincheckCore.this.secret), sha256()) );
            }};
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object httpCode, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;
        }
        //
        //     {"success":false,"error":"disabled API Key"}'
        //     {"success":false,"error":"invalid authentication"}
        //
        Object success = this.safeBool(response, "success", true);
        if (!Helpers.isTrue(success))
        {
            Object error = this.safeString(response, "error");
            Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(response));
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), error, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), body, feedback);
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " "), this.json(response))) ;
        }
        return null;
    }
